# ==============================================================================
# PALETTE & HELPERS
# ==============================================================================
OLIVE    = "#2C3A2E"
CREAM    = "#F5F2ED"
GREEN_LT = "#8FA87E"
RED      = "#C0392B"
AMBER    = "#D35400"
TEAL     = "#0D6E6E"

PLOTLY_THEME = dict(
    paper_bgcolor="white",
    plot_bgcolor="#FAFAF8",
    font_family="Inter",
    font_color=OLIVE,
    title_text="",
    title_font_size=15,
    title_font_color=OLIVE,
    margin=dict(l=24, r=24, t=44, b=24),
)


def fmt(n):
    """Format angka besar."""
    if n >= 1_000_000: return f"{n/1_000_000:.1f}jt"
    if n >= 1_000:     return f"{n/1_000:.1f}rb"
    return str(int(n))


def kpi(label, value, cls="", delta=""):
    return f"""
    <div class="kpi-card {cls}">
        <div class="kpi-label">{label}</div>
        <div class="kpi-value">{value}</div>
        {'<div class="kpi-delta">'+delta+'</div>' if delta else ''}
    </div>"""


# ==============================================================================
# DATA LOADING (cached)
# ==============================================================================
@st.cache_data(show_spinner="Memuat data...")
def load_data():
    proc = PATHS["processed"]
    feat = PATHS["features"]
    result = {}
    for prefix in ["bnpb", "combine", "cuaca"]:
        files = sorted([f for f in os.listdir(proc)
                        if f.startswith(prefix) and f.endswith(".csv")])
        result[prefix] = pd.read_csv(os.path.join(proc, files[-1])) if files else pd.DataFrame()

    ff = sorted([f for f in os.listdir(feat) if f.endswith(".csv")])
    result["fitur"] = pd.read_csv(os.path.join(feat, ff[-1])) if ff else pd.DataFrame()
    return result


