# ==============================================================================
# KPI ROW
# ==============================================================================
def render_kpis(df_bnpb, df_fitur):
    st.markdown('<div class="section-heading">Ringkasan Data</div>', unsafe_allow_html=True)
    st.markdown('<div class="section-caption">Akumulasi dari seluruh sumber data yang telah diproses</div>', unsafe_allow_html=True)

    c1, c2, c3, c4, c5 = st.columns(5)

    total_kejadian = len(df_bnpb) if not df_bnpb.empty else 0
    total_korban   = int(df_bnpb["korban_meninggal"].sum()) if (not df_bnpb.empty and "korban_meninggal" in df_bnpb.columns) else 0
    total_rumah    = int(df_bnpb["rumah_terendam"].sum())   if (not df_bnpb.empty and "rumah_terendam"   in df_bnpb.columns) else 0
    total_prov     = df_bnpb["provinsi"].nunique()           if (not df_bnpb.empty and "provinsi"        in df_bnpb.columns) else 0
    total_kritis   = 0
    if not df_fitur.empty and "status_risiko" in df_fitur.columns:
        total_kritis = int((df_fitur["status_risiko"] == "kritis").sum())

    with c1: st.markdown(kpi("Total Kejadian", fmt(total_kejadian), "", "Data BNPB DIBI"), unsafe_allow_html=True)
    with c2: st.markdown(kpi("Korban Meninggal", fmt(total_korban), "kpi-red", "Akumulasi"), unsafe_allow_html=True)
    with c3: st.markdown(kpi("Rumah Terendam", fmt(total_rumah), "kpi-amber", "Akumulasi"), unsafe_allow_html=True)
    with c4: st.markdown(kpi("Provinsi Terdampak", str(total_prov), "kpi-teal", "Dari 34 Provinsi"), unsafe_allow_html=True)
    with c5: st.markdown(kpi("Prediksi Status Kritis", fmt(total_kritis), "kpi-red", "Dari Feature Set ML"), unsafe_allow_html=True)

    st.markdown('<div class="olive-divider"></div>', unsafe_allow_html=True)


# ==============================================================================
# TAB 1 - Overview & Tren
# ==============================================================================
def tab_overview(df_bnpb, df_fitur):
    st.markdown(f'<div style="margin-bottom:1.5rem;"><h2 style="margin:0; font-weight:700;">{img_html("icon_overview.png", 40)}Overview & Tren</h2></div>', unsafe_allow_html=True)

    # --- Chart 1: Top Provinsi ---
    col_chart, col_insight = st.columns([2, 1], gap="large")
    with col_chart:
        st.markdown('<div class="section-heading">Top 15 Provinsi Rawan Banjir</div>', unsafe_allow_html=True)
        if not df_bnpb.empty and "provinsi" in df_bnpb.columns:
            top = (df_bnpb.groupby("provinsi").size()
                          .reset_index(name="jumlah")
                          .sort_values("jumlah", ascending=False).head(15))
            fig = px.bar(top, x="jumlah", y="provinsi", orientation="h",
                         color="jumlah",
                         color_continuous_scale=["#C8D4B8", "#2C3A2E"])
            fig.update_layout(**PLOTLY_THEME, height=420,
                              coloraxis_showscale=False,
                              yaxis=dict(categoryorder="total ascending"))
            fig.update_traces(hovertemplate="<b>%{y}</b><br>Kejadian: %{x:,}<extra></extra>")
            st.plotly_chart(fig, use_container_width=True)

    with col_insight:
        st.markdown('<div style="height:2.5rem"></div>', unsafe_allow_html=True)
        if not df_bnpb.empty and "provinsi" in df_bnpb.columns:
            top3 = (df_bnpb.groupby("provinsi").size()
                           .reset_index(name="jumlah")
                           .sort_values("jumlah", ascending=False).head(3))
            for _, r in top3.iterrows():
                st.markdown(f"""
                <div class="insight-card">
                    <h5>#{list(top3.index).index(_)+1} {r['provinsi']}</h5>
                    <p>{r['jumlah']:,} kejadian banjir tercatat</p>
                </div>""", unsafe_allow_html=True)

    # --- Chart 2: Tren Tahunan ---
    st.markdown('<div class="section-heading" style="margin-top:1.2rem">Tren Banjir Tahunan</div>', unsafe_allow_html=True)
    st.markdown('<div class="section-caption">Jumlah kejadian & korban meninggal per tahun</div>', unsafe_allow_html=True)

    if not df_bnpb.empty and "tahun" in df_bnpb.columns:
        tren = (df_bnpb.groupby("tahun")
                       .agg(jumlah=("tahun","count"),
                            korban=("korban_meninggal","sum"))
                       .reset_index())
        fig2 = make_subplots(specs=[[{"secondary_y": True}]])
        fig2.add_trace(go.Bar(x=tren["tahun"], y=tren["jumlah"],
                              name="Kejadian", marker_color=OLIVE,
                              opacity=0.85), secondary_y=False)
        fig2.add_trace(go.Scatter(x=tren["tahun"], y=tren["korban"],
                                  name="Korban Meninggal",
                                  line=dict(color=RED, width=2.5),
                                  mode="lines+markers",
                                  marker=dict(size=7)), secondary_y=True)
        fig2.update_layout(**PLOTLY_THEME, height=360,
                           legend=dict(orientation="h", yanchor="bottom",
                                       y=1.02, xanchor="right", x=1))
        fig2.update_yaxes(title_text="Jumlah Kejadian", secondary_y=False)
        fig2.update_yaxes(title_text="Korban Meninggal", secondary_y=True)
        st.plotly_chart(fig2, use_container_width=True)


