def _get_warning_level(avg_rain):
    """Tentukan level peringatan berdasarkan curah hujan rata-rata."""
    if avg_rain >= 100:
        return "kritis", "KRITIS", get_css_circle("#D32F2F"), "Curah hujan sangat tinggi! Potensi banjir besar."
    elif avg_rain >= 50:
        return "tinggi", "TINGGI", get_css_circle("#F57C00"), "Curah hujan tinggi. Waspada potensi banjir."
    elif avg_rain >= 20:
        return "sedang", "SEDANG", get_css_circle("#FBC02D"), "Curah hujan sedang. Pantau perkembangan."
    else:
        return "rendah", "RENDAH", get_css_circle("#388E3C"), "Curah hujan rendah. Kondisi aman."


def _render_early_warning(df_fitur, df_cuaca):
    """Render early warning detection section."""
    st.markdown(f'<div class="section-heading">{img_html("icon_alert.png", 32)}Sistem Peringatan Dini Banjir</div>', unsafe_allow_html=True)
    st.markdown('<div class="section-caption">Deteksi otomatis wilayah berisiko berdasarkan data curah hujan dan indeks risiko</div>', unsafe_allow_html=True)

    if df_fitur.empty or "avg_rainfall" not in df_fitur.columns:
        st.info("Data fitur tidak tersedia untuk analisis peringatan dini.")
        return

    # Overall risk gauge
    overall_rain = df_fitur["avg_rainfall"].mean()
    level_cls, level_label, level_icon, level_msg = _get_warning_level(overall_rain)

    col_gauge, col_summary = st.columns([1, 2], gap="large")

    with col_gauge:
        fig_gauge = go.Figure(go.Indicator(
            mode="gauge+number+delta",
            value=round(overall_rain, 1),
            number={"suffix": " mm", "font": {"size": 36, "family": "Inter", "color": OLIVE}},
            title={"text": "Curah Hujan Rata-rata", "font": {"size": 14, "family": "Inter"}},
            gauge={
                "axis": {"range": [0, 200], "tickwidth": 1},
                "bar": {"color": "#2C3A2E"},
                "bgcolor": "#F5F2ED",
                "steps": [
                    {"range": [0, 20], "color": "#E8F5E9"},
                    {"range": [20, 50], "color": "#FFF8E1"},
                    {"range": [50, 100], "color": "#FFF3E0"},
                    {"range": [100, 200], "color": "#FFEBEE"},
                ],
                "threshold": {
                    "line": {"color": RED, "width": 3},
                    "thickness": 0.8,
                    "value": 100,
                },
            },
        ))
        fig_gauge.update_layout(
            paper_bgcolor="white", font_family="Inter",
            height=250, margin=dict(l=30, r=30, t=50, b=10)
        )
        st.plotly_chart(fig_gauge, use_container_width=True)

    with col_summary:
        st.markdown(f"""
        <div class="alert-card alert-{level_cls}">
            <div class="alert-level">{level_icon} STATUS PERINGATAN: {level_label}</div>
            <div class="alert-title">{level_msg}</div>
            <p class="alert-detail">Curah hujan rata-rata keseluruhan: <b>{overall_rain:.1f} mm/hari</b></p>
        </div>""", unsafe_allow_html=True)

        # Count regions per risk level
        if "status_risiko" in df_fitur.columns:
            risk_counts = df_fitur["status_risiko"].value_counts()
            kritis_n = risk_counts.get("kritis", 0)
            tinggi_n = risk_counts.get("tinggi", 0)
            sedang_n = risk_counts.get("sedang", 0)
            rendah_n = risk_counts.get("rendah", 0)

            c1, c2, c3, c4 = st.columns(4)
            c1.metric("Kritis", f"{kritis_n:,}")
            c2.metric("Tinggi", f"{tinggi_n:,}")
            c3.metric("Sedang", f"{sedang_n:,}")
            c4.metric("Rendah", f"{rendah_n:,}")

    # High-risk regions detail
    st.markdown('<div class="olive-divider"></div>', unsafe_allow_html=True)
    st.markdown(f'<div class="section-heading" style="font-size:1.3rem">{img_html("icon_alert.png", 24)}Wilayah Berisiko Tinggi & Kritis</div>', unsafe_allow_html=True)

    high_risk = df_fitur.copy()
    if "status_risiko" in high_risk.columns:
        high_risk = high_risk[high_risk["status_risiko"].isin(["tinggi", "kritis"])]

    if high_risk.empty:
        st.success("✓ Tidak ada wilayah dengan status risiko tinggi atau kritis saat ini.")
    else:
        display_cols = [c for c in ["kabupaten", "avg_rainfall", "max_rainfall",
                                     "status_risiko", "risiko_index", "elevation",
                                     "ndvi", "soil_moisture"] if c in high_risk.columns]
        hr_display = high_risk[display_cols].sort_values(
            "risiko_index" if "risiko_index" in display_cols else "avg_rainfall",
            ascending=False
        ).head(20)

        col_rename = {
            "kabupaten": "Kabupaten", "avg_rainfall": "Curah Hujan (mm)",
            "max_rainfall": "Curah Hujan Maks", "status_risiko": "Status Risiko",
            "risiko_index": "Indeks Risiko", "elevation": "Elevasi (m)",
            "ndvi": "NDVI", "soil_moisture": "Kelembapan Tanah"
        }
        hr_display = hr_display.rename(columns=col_rename)

        def _color_risk(val):
            colors = {"kritis": "background-color: #FFCDD2; color: #B71C1C; font-weight:700",
                      "tinggi": "background-color: #FFE0B2; color: #E65100; font-weight:700"}
            return colors.get(val, "")

        if "Status Risiko" in hr_display.columns:
            styled = hr_display.style.applymap(_color_risk, subset=["Status Risiko"])
            st.dataframe(styled, use_container_width=True, hide_index=True, height=400)
        else:
            st.dataframe(hr_display, use_container_width=True, hide_index=True, height=400)


