def _render_detail_table(df_bnpb, df_fitur):
    """Render filterable detail table of flood events."""
    st.markdown(f'<div class="section-heading">{img_html("icon_table.png", 32)}Detail Kejadian Banjir</div>', unsafe_allow_html=True)
    st.markdown('<div class="section-caption">Tabel interaktif dengan filter waktu, lokasi, dan faktor penyebab</div>', unsafe_allow_html=True)

    # Use df_fitur if it has banjir-related cols, else fall back to df_bnpb
    if not df_fitur.empty and "kabupaten" in df_fitur.columns and "avg_rainfall" in df_fitur.columns:
        df = df_fitur.copy()
        source = "fitur"
    elif not df_bnpb.empty:
        df = df_bnpb.copy()
        source = "bnpb"
    else:
        st.info("Tidak ada data yang tersedia untuk ditampilkan.")
        return

    # --- Filters ---
    st.markdown('<div class="filter-bar">', unsafe_allow_html=True)
    fcol1, fcol2, fcol3, fcol4 = st.columns(4, gap="small")

    with fcol1:
        if source == "fitur" and "kabupaten" in df.columns:
            kab_opts = sorted(df["kabupaten"].dropna().unique().tolist())
            kab_sel = st.multiselect("Kabupaten", kab_opts, placeholder="Semua", key="f_kab")
        elif source == "bnpb" and "kabupaten" in df.columns:
            kab_opts = sorted(df["kabupaten"].dropna().unique().tolist())
            kab_sel = st.multiselect("Kabupaten", kab_opts, placeholder="Semua", key="f_kab")
        else:
            kab_sel = []

    with fcol2:
        if "musim" in df.columns:
            musim_opts = sorted(df["musim"].dropna().unique().tolist())
            musim_sel = st.multiselect("Musim", musim_opts, placeholder="Semua", key="f_musim")
        else:
            musim_sel = []

    with fcol3:
        if "status_risiko" in df.columns:
            risk_opts = ["rendah", "sedang", "tinggi", "kritis"]
            risk_available = [r for r in risk_opts if r in df["status_risiko"].unique()]
            risk_sel = st.multiselect("Status Risiko", risk_available, placeholder="Semua", key="f_risk")
        else:
            risk_sel = []

    with fcol4:
        if "label_banjir" in df.columns:
            banjir_opt = st.selectbox("Status Banjir", ["Semua", "Banjir", "Tidak Banjir"], key="f_banjir")
        else:
            banjir_opt = "Semua"

    st.markdown('</div>', unsafe_allow_html=True)

    # Apply filters
    if kab_sel and "kabupaten" in df.columns:
        df = df[df["kabupaten"].isin(kab_sel)]
    if musim_sel and "musim" in df.columns:
        df = df[df["musim"].isin(musim_sel)]
    if risk_sel and "status_risiko" in df.columns:
        df = df[df["status_risiko"].isin(risk_sel)]
    if banjir_opt != "Semua" and "label_banjir" in df.columns:
        target_val = True if banjir_opt == "Banjir" else False
        df = df[df["label_banjir"] == target_val]

    # Summary metrics
    m1, m2, m3, m4 = st.columns(4)
    m1.metric("Total Data", f"{len(df):,}")
    if source == "bnpb" and "korban_meninggal" in df.columns:
        m2.metric("Total Korban", f"{int(df['korban_meninggal'].sum()):,}")
    elif source == "fitur" and "avg_rainfall" in df.columns:
        m2.metric("Avg Curah Hujan", f"{df['avg_rainfall'].mean():.1f} mm")
    if "kabupaten" in df.columns:
        m3.metric("Jumlah Kabupaten", f"{df['kabupaten'].nunique():,}")
    if "label_banjir" in df.columns:
        m4.metric("Kejadian Banjir", f"{int(df['label_banjir'].sum()):,}")
    elif "terjadi_banjir" in df.columns:
        m4.metric("Kejadian Banjir", f"{int((df['terjadi_banjir'] == True).sum()):,}")

    # Select display columns
    if source == "fitur":
        show_cols = [c for c in ["kabupaten", "tanggal", "year", "month", "musim",
                                  "avg_rainfall", "max_rainfall", "avg_temperature",
                                  "elevation", "ndvi", "soil_moisture",
                                  "label_banjir", "status_risiko", "risiko_index"
                                  ] if c in df.columns]
    else:
        show_cols = [c for c in ["tanggal", "kejadian", "kabupaten", "provinsi",
                                  "korban_meninggal", "korban_hilang", "korban_terluka",
                                  "rumah_rusak", "rumah_terendam", "tahun", "bulan", "musim"
                                  ] if c in df.columns]

    col_rename_detail = {
        "kabupaten": "Kabupaten", "tanggal": "Tanggal", "year": "Tahun",
        "month": "Bulan", "musim": "Musim", "avg_rainfall": "Curah Hujan (mm)",
        "max_rainfall": "CH Maks (mm)", "avg_temperature": "Suhu (\u00b0C)",
        "elevation": "Elevasi (m)", "ndvi": "NDVI", "soil_moisture": "Kelembapan",
        "label_banjir": "Banjir?", "status_risiko": "Risiko",
        "risiko_index": "Indeks Risiko", "kejadian": "Kejadian",
        "provinsi": "Provinsi", "korban_meninggal": "Meninggal",
        "korban_hilang": "Hilang", "korban_terluka": "Terluka",
        "rumah_rusak": "Rumah Rusak", "rumah_terendam": "Rumah Terendam",
        "tahun": "Tahun", "bulan": "Bulan"
    }

    df_display = df[show_cols].rename(columns=col_rename_detail)
    st.dataframe(df_display, use_container_width=True, hide_index=True, height=500)


def tab_data_warning(df_bnpb, df_fitur, df_cuaca):
    """Tab 4: Data & Peringatan - menggabungkan ekspor, early warning, dan detail tabel."""
    st.markdown(f'<div style="margin-bottom:1.5rem;"><h2 style="margin:0; font-weight:700;">{img_html("icon_alert.png", 40)}Data & Peringatan</h2></div>', unsafe_allow_html=True)

    # Section 1: Early Warning Detection
    _render_early_warning(df_fitur, df_cuaca)

    st.markdown('<div class="olive-divider"></div>', unsafe_allow_html=True)

    # Section 2: Export Data
    _render_export(df_bnpb, df_fitur, df_cuaca)

    st.markdown('<div class="olive-divider"></div>', unsafe_allow_html=True)

    # Section 3: Detail Data Table
    _render_detail_table(df_bnpb, df_fitur)


# ==============================================================================
# MAIN APP
# ==============================================================================
def main():
    data = load_data()
    df_bnpb    = data.get("bnpb",    pd.DataFrame())
    df_combine = data.get("combine", pd.DataFrame())
    df_cuaca   = data.get("cuaca",   pd.DataFrame())
    df_fitur   = data.get("fitur",   pd.DataFrame())

    # Apply column renames for display
    if not df_bnpb.empty:
        rename = {
            "tanggal_kejadian": "tanggal",
            "Meninggal": "korban_meninggal",
            "Hilang": "korban_hilang",
            "Terluka": "korban_terluka",
            "Rumah Rusak": "rumah_rusak",
            "Rumah Terendam": "rumah_terendam",
            "Provinsi": "provinsi",
            "Kabupaten": "kabupaten",
        }
        df_bnpb = df_bnpb.rename(columns={k:v for k,v in rename.items() if k in df_bnpb.columns})
        if "tanggal" in df_bnpb.columns:
            df_bnpb["tanggal"] = pd.to_datetime(df_bnpb["tanggal"], errors="coerce")
            df_bnpb["tahun"]   = df_bnpb["tanggal"].dt.year

    df_fitur_display = df_fitur if not df_fitur.empty else df_combine

    # Sidebar & Filters
    tahun_sel, prov_sel = render_sidebar(df_bnpb, df_fitur_display)

    # Terapkan filter
    df_filtered = df_bnpb.copy()
    if not df_filtered.empty and "tahun" in df_filtered.columns:
        df_filtered = df_filtered[
            df_filtered["tahun"].between(tahun_sel[0], tahun_sel[1])
        ]
    if prov_sel and "provinsi" in df_filtered.columns:
        df_filtered = df_filtered[df_filtered["provinsi"].isin(prov_sel)]

    # Hero Section
    render_hero()

    # KPI Row
    render_kpis(df_filtered, df_fitur_display)

    # Main Content - Tabs
    tab1, tab2, tab3, tab4 = st.tabs([
        "Overview & Tren",
        "Lingkungan & Cuaca",
        "Machine Learning",
        "Data & Peringatan"
    ])

    with tab1:
        tab_overview(df_filtered, df_fitur_display)
    with tab2:
        tab_lingkungan(df_fitur_display, df_cuaca)
    with tab3:
        tab_ml(df_fitur_display)
    with tab4:
        tab_data_warning(df_filtered, df_fitur_display, df_cuaca)

    # Footer
    st.markdown("""
    <div class="footer">
        <img src='data:image/png;base64,' style='height:1.2em; margin:0 5px; vertical-align:middle;'> FloodWatch Indonesia &nbsp;·&nbsp; Pipeline MKPL v2 &nbsp;·&nbsp;
        Data: BNPB DIBI, Master Cuaca, Dataset ML Gabungan &nbsp;·&nbsp;
        Dibuat dengan Streamlit &amp; Plotly
    </div>""", unsafe_allow_html=True)


if __name__ == "__main__":
    main()
